					ptmx.Write([]byte("\x1b[B")) // Down arrow
					time.Sleep(200 * time.Millisecond)
					ptmx.Write([]byte("\r")) // Enter
				}

				if !gotResults && (strings.Contains(clean, "SEA_SMOKE_PASS") || strings.Contains(clean, "SEA_SMOKE_FAIL")) {
