package cli

import (
	"bufio"
	"fmt"
	"io"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
	"time"

	"github.com/creack/pty"
	"github.com/spf13/cobra"
	"gopkg.in/yaml.v3"

	"github.com/agentsea/agentsea/internal/detect"
	"github.com/agentsea/agentsea/internal/workspace"
)

func smokeCmd() *cobra.Command {
	var timeout time.Duration

	cmd := &cobra.Command{
		Use:   "smoke",
		Short: "End-to-end smoke test of teammate sandboxing",
		Long: `Creates a temporary project, launches Claude Code interactively in a PTY
with sandboxing enabled, and instructs it to spawn a teammate that verifies
its bwrap sandbox environment.

The lead agent spawns a real teammate via CLAUDE_CODE_TEAMMATE_COMMAND,
which goes through the full teammate-wrapper → bwrap pipeline.

Requires no existing repos or network connection.`,
		RunE: func(cmd *cobra.Command, args []string) error {
			return runSmoke(timeout)
		},
	}

	cmd.Flags().DurationVar(&timeout, "timeout", 5*time.Minute, "Maximum time to wait for smoke test")
	return cmd
}

// smokeConfig holds resolved paths for the smoke test environment.
type smokeConfig struct {
	TmpDir     string
	ClaudeBin  string
	SeaBin     string
	WrapperBin string // path to the teammate-wrapper shell script
}

// smokePreflight validates the environment and creates the temp project.
func smokePreflight() (*smokeConfig, error) {
	claudeBin, err := detect.FindClaudeBinary()
	if err != nil {
		return nil, fmt.Errorf("finding claude binary: %w", err)
	}

	seaBin, err := os.Executable()
	if err != nil {
		return nil, fmt.Errorf("resolving sea binary path: %w", err)
	}

	if _, err := exec.LookPath("bwrap"); err != nil {
		return nil, fmt.Errorf("bwrap not found on PATH — install with: sudo apt install bubblewrap")
	}

	tmpDir, err := os.MkdirTemp("", "sea-smoke-*")
	if err != nil {
		return nil, fmt.Errorf("creating temp dir: %w", err)
	}

	return &smokeConfig{
		TmpDir:    tmpDir,
		ClaudeBin: claudeBin,
		SeaBin:    seaBin,
	}, nil
}

// smokeSetup initializes a self-contained git repo and workspace with no
// network access or pre-existing repos required.
func smokeSetup(cfg *smokeConfig) error {
	for name, content := range map[string]string{
		"CLAUDE.md": smokeClaudeMD,
		"README.md": "# Smoke Test Project\n",
	} {
		if err := os.WriteFile(filepath.Join(cfg.TmpDir, name), []byte(content), 0644); err != nil {
			return fmt.Errorf("writing %s: %w", name, err)
		}
	}

	gitEnv := append(os.Environ(),
		"GIT_AUTHOR_NAME=sea-smoke",
		"GIT_AUTHOR_EMAIL=smoke@test",
		"GIT_COMMITTER_NAME=sea-smoke",
		"GIT_COMMITTER_EMAIL=smoke@test",
	)
	for _, args := range [][]string{
