func runSmoke(timeout time.Duration) error {
	cfg, err := smokePreflight()
	if err != nil {
		return err
	}

	fmt.Printf("Setting up smoke test in %s\n", cfg.TmpDir)

	if err := smokeSetup(cfg); err != nil {
		os.RemoveAll(cfg.TmpDir)
		return err
	}

	fmt.Printf("  claude:  %s\n", cfg.ClaudeBin)
	fmt.Printf("  wrapper: %s\n", cfg.WrapperBin)
	fmt.Printf("  project: %s\n", cfg.TmpDir)
	fmt.Printf("  timeout: %s\n", timeout)
	fmt.Println()
	fmt.Printf("Clean up after: rm -rf %s\n", cfg.TmpDir)
	fmt.Println()

	// Launch claude in true interactive mode (NOT --print) so the Agent
	// tool is available for teammate spawning. --print mode disables the
	// Agent tool entirely. The prompt is passed as a positional argument
	// which auto-submits in the interactive TUI.
	//
	// With TMUX set in the environment, teammate mode "auto" resolves to
	// "tmux" — creating a new tmux pane that invokes CLAUDE_CODE_TEAMMATE_COMMAND.
	cmd := exec.Command(cfg.ClaudeBin,
		"--dangerously-skip-permissions",
		smokePrompt,
	)
	cmd.Dir = cfg.TmpDir
	cmd.Env = append(os.Environ(),
		fmt.Sprintf("CLAUDE_CODE_TEAMMATE_COMMAND=%s", cfg.WrapperBin),
	)

	// Start claude in a PTY
	ptmx, err := pty.Start(cmd)
	if err != nil {
		return fmt.Errorf("starting claude in PTY: %w", err)
	}
	defer ptmx.Close()

	// Set PTY size
	pty.Setsize(ptmx, &pty.Winsize{Rows: 50, Cols: 120})

	fmt.Println("Launched Claude Code in PTY, waiting for smoke test results...")
	fmt.Println()

	// Read PTY output, scanning for results
	var output strings.Builder
	gotResults := false
	resultsFound := make(chan struct{}, 1)

	go func() {
		reader := bufio.NewReader(ptmx)
		for {
			line, err := reader.ReadString('\n')
			if line != "" {
				clean := stripANSI(line)
				fmt.Print(clean)
				output.WriteString(clean)

				// Auto-dismiss interactive dialogs:
				// 1. Trust dialog: "Yes, I trust this folder" is pre-selected → Enter
				// 2. Bypass permissions: "No, exit" is pre-selected → Down then Enter
				if strings.Contains(clean, "trust") && strings.Contains(clean, "folder") {
					time.Sleep(500 * time.Millisecond)
					ptmx.Write([]byte("\r"))
				}
				if strings.Contains(clean, "accept") && strings.Contains(clean, "responsibility") {
					time.Sleep(500 * time.Millisecond)
					ptmx.Write([]byte("\x1b[B")) // Down arrow
					time.Sleep(200 * time.Millisecond)
					ptmx.Write([]byte("\r")) // Enter
				}

				if !gotResults && strings.Contains(clean, "SENTINEL_DONE") {
					gotResults = true
					select {
					case resultsFound <- struct{}{}:
					default:
					}
				}
			}
			if err != nil {
				if err != io.EOF {
					fmt.Fprintf(os.Stderr, "[sea] PTY read error: %v\n", err)
				}
				return
			}
		}
	}()

	// Wait for results, process exit, or timeout.
	// Interactive mode doesn't exit on its own, so we kill after
	// collecting results (with a grace period to capture remaining output).
	timer := time.NewTimer(timeout)
	defer timer.Stop()

	cmdDone := make(chan error, 1)
	go func() {
		cmdDone <- cmd.Wait()
	}()

	select {
	case <-resultsFound:
		// Give Claude a few seconds to finish printing the summary
		time.Sleep(3 * time.Second)
		fmt.Fprintf(os.Stderr, "\n[sea] Results detected — stopping claude\n")
		cmd.Process.Kill()
		cmd.Wait()
	case err := <-cmdDone:
		time.Sleep(100 * time.Millisecond)
		if err != nil {
			fmt.Fprintf(os.Stderr, "\n[sea] claude exited with: %v\n", err)
		}
	case <-timer.C:
		fmt.Fprintf(os.Stderr, "\n[sea] Timeout after %s — killing claude\n", timeout)
		cmd.Process.Kill()
		cmd.Wait()
	}

	fmt.Println()
	if gotResults {
		fmt.Println("Smoke test completed.")
	} else {
		fmt.Println("Smoke test did not produce expected SENTINEL_DONE marker.")
	}
	fmt.Printf("Inspect workspace: %s\n", cfg.TmpDir)
	return nil
}

// stripANSI removes ANSI escape sequences from a string.
func stripANSI(s string) string {
	var out strings.Builder
	i := 0
	for i < len(s) {
		if s[i] == '\x1b' {
			// Skip ESC [ ... (letter)
			i++
			if i < len(s) && s[i] == '[' {
				i++
				for i < len(s) && !((s[i] >= 'A' && s[i] <= 'Z') || (s[i] >= 'a' && s[i] <= 'z')) {
					i++
				}
				if i < len(s) {
					i++ // skip the final letter
				}
			}
		} else {
			out.WriteByte(s[i])
			i++
		}
	}
	return out.String()
}

